<script setup lang="ts">import type { BpmPolicyReference,BpmPolicyTechnicalDetail,BpmPolicyTechnicalDiff } from '#/api/system/bpm/policy'; import { onMounted,ref } from 'vue'; import { ElButton,ElCollapse,ElCollapseItem,ElDescriptions,ElDescriptionsItem,ElInput,ElInputNumber,ElTag } from 'element-plus'; import { diffBpmPolicyTechnicalDetail,getBpmPolicyTechnicalDetail } from '#/api/system/bpm/policy'; const props=defineProps<{reference:BpmPolicyReference}>(); const detail=ref<BpmPolicyTechnicalDetail>();const compareVersion=ref(Math.max(1,props.reference.policyVersion-1));const diff=ref<BpmPolicyTechnicalDiff>();onMounted(async()=>{detail.value=await getBpmPolicyTechnicalDetail(props.reference)});async function compare(){diff.value=await diffBpmPolicyTechnicalDetail({...props.reference,policyVersion:compareVersion.value},props.reference)}</script>
<template><ElCollapse v-if="detail"><ElCollapseItem title="技术协议（只读）"><ElDescriptions :column="1" border><ElDescriptionsItem label="Schema">v{{detail.schemaVersion}}</ElDescriptionsItem><ElDescriptionsItem label="摘要">{{detail.digest}}</ElDescriptionsItem></ElDescriptions><div class="compare"><span>对比版本</span><ElInputNumber v-model="compareVersion" :min="1"/><ElButton @click="compare">版本对比</ElButton><ElTag v-for="path in diff?.changedPaths" :key="path" effect="plain">{{path}}</ElTag></div><ElInput class="mt-3" :model-value="detail.canonicalPayload" :rows="14" readonly type="textarea"/></ElCollapseItem></ElCollapse></template><style scoped>.compare{display:flex;align-items:center;flex-wrap:wrap;gap:8px;margin-top:12px}</style>
